import subprocess
from google.cloud import storage

def convert_image(event, context):
    bucket_name = event['bucket']
    file_name = event['name']

    # Extract conversion options from event metadata
    conversion_options = event.get('conversionOptions', [])

    # Construct the command to run ImageMagick's convert command
    cmd = f"convert {file_name} -{conversion_options[0]} output_{file_name}"

    try:
        subprocess.call(cmd, shell=True)
    except Exception as e:
        print(f"Error converting image: {e}")

